<?php
declare(strict_types=1);
require_once __DIR__.'/app/bootstrap.php';
$user=Auth::requireUser();Auth::start();$uid=(int)$user['id'];$id=max(0,(int)($_GET['id']??$_POST['id']??0));$pdo=Database::connection();$drafts=new MockupPinterestDraftService($pdo);$batches=new PinterestBatchService($pdo,$drafts);$pinterest=new PinterestIntegrationService($pdo);
$error=(string)($_SESSION['pinterest_batch_error']??'');$notice=(string)($_SESSION['pinterest_batch_notice']??'');unset($_SESSION['pinterest_batch_error'],$_SESSION['pinterest_batch_notice']);
$linkedCampaign=(new SocialCampaignPinterestBridge($pdo))->linkedCampaign($id,$uid);
$backHref=$linkedCampaign?'social_media_catalog.php?draft='.(int)$linkedCampaign['id']:'mockups.php';
$backLabel=$linkedCampaign?'← Social campaign':'← Mockup Album';
try{$batch=$batches->batch($id,$uid);$boards=$pinterest->boards($uid,(string)$batch['purpose']);$items=$batches->items($id,$uid);if($_SERVER['REQUEST_METHOD']==='POST'){if(!hash_equals((string)($_SESSION['pinterest_batch_csrf']??''),(string)($_POST['csrf']??'')))throw new RuntimeException('The batch review expired.');$draftId=(int)($_POST['draft_id']??0);$draft=$drafts->draft($draftId,$uid);if(!in_array($draftId,array_map(fn($r)=>(int)$r['id'],$items),true))throw new RuntimeException('Draft does not belong to this batch.');$action=(string)($_POST['action']??'');if($action==='save_crop'){$drafts->saveCrop($draftId,$uid,(float)($_POST['crop_x']??.5),(float)($_POST['crop_y']??.5),(float)($_POST['crop_zoom']??1));$notice='Crop saved.';}elseif($action==='save_destination'){$drafts->updateDestination($draftId,$uid,trim((string)($_POST['destination_url']??'')));$notice='Destination saved.';}else{$batches->selectBoards($draft,$uid,(array)($_POST['board_ids']??[]),$boards);$notice='Boards saved.';}$items=$batches->items($id,$uid);}}catch(Throwable $e){$error=$e->getMessage();$batch=$batch??null;$boards=$boards??[];$items=$items??[];}
$_SESSION['pinterest_batch_csrf']=bin2hex(random_bytes(24));$_SESSION['pinterest_batch_publish_csrf']=bin2hex(random_bytes(24));$readyPins=0;$readyCards=0;foreach($items as $item){$destinations=$batches->destinations((int)$item['id']);$validDestination=filter_var((string)$item['destination_url'],FILTER_VALIDATE_URL)&&strtolower((string)parse_url((string)$item['destination_url'],PHP_URL_SCHEME))==='https';if(($item['variant_file']??'')!==''&&$destinations&&$validDestination){$readyCards++;$readyPins+=count(array_filter($destinations,fn($d)=>($d['status']??'')!=='published'));}}function pbh($v):string{return htmlspecialchars((string)$v,ENT_QUOTES,'UTF-8');}
?>
<!doctype html><html lang="en"><head><meta charset="utf-8"><meta name="viewport" content="width=device-width,initial-scale=1"><title>Pinterest Batch Review</title><link rel="stylesheet" href="style.css"><style>
.batch-grid{display:grid;grid-template-columns:repeat(auto-fit,minmax(340px,1fr));gap:12px}.batch-card{min-width:0;border:1px solid var(--line);background:var(--surface);padding:10px;border-radius:10px}.batch-card canvas{width:100%;aspect-ratio:2/3;background:#111;display:block;cursor:grab;touch-action:none}.batch-card input[type=url],.batch-card input[type=text],.batch-card textarea{width:100%;padding:8px;font-size:12px}.batch-card textarea{resize:vertical;line-height:1.35}.destination-form{margin:8px 0}.boards-label,.content-label{display:block;margin:8px 0 4px;font-size:10px;font-weight:700;letter-spacing:.05em;text-transform:uppercase}.boards{display:grid;grid-template-columns:1fr 1fr;gap:3px;margin:0 0 6px}.board{position:relative;display:flex;align-items:center;min-height:30px;padding:4px 6px;border:1px solid var(--line);border-radius:5px;cursor:pointer;font-size:9px;line-height:1.1}.board input{position:absolute;opacity:0}.board:has(input:checked){border-color:#bd081c;background:rgba(189,8,28,.06);box-shadow:inset 2px 0 #bd081c}.board.published{opacity:.48;cursor:not-allowed}.content-form{display:grid;gap:6px}.keyword-list{display:flex;flex-wrap:wrap;gap:4px;margin-top:5px}.keyword-list span{padding:3px 6px;background:var(--surface-soft);border-radius:999px;font-size:9px}.status{display:block;margin-top:7px;font-size:11px;color:#796457}.pin-error{margin:8px 0 0;padding:8px;background:#fff1ef;color:#8a3028;font-size:11px;line-height:1.35}@media(max-width:1100px){.batch-grid{grid-template-columns:repeat(2,minmax(0,1fr))}}@media(max-width:700px){.batch-grid,.boards{grid-template-columns:1fr}}
</style></head><body><div class="app-shell"><?php include __DIR__.'/sidebar.php';?><main class="main-area"><div class="workspace"><div class="workspace-header"><div><h1>Pinterest batch #<?=$id?></h1><p><?=count($items)?> mockup cards · maximum 3 boards each.<?php if($linkedCampaign):?> · <?=pbh($linkedCampaign['title'])?><?php endif;?></p></div><a class="button-link secondary" href="<?=pbh($backHref)?>"><?=pbh($backLabel)?></a></div>
<?php if($error):?><div class="notice error"><?=pbh($error)?></div><?php endif;?><?php if($notice):?><div class="notice success"><?=pbh($notice)?></div><?php endif;?><div class="batch-grid">
<?php foreach($items as $item):$destinations=$batches->destinations((int)$item['id']);$selected=array_column($destinations,'board_id');$published=$batches->publishedBoardIds($uid,(int)$item['mockup_id'],(string)$item['purpose']);?>
<article class="batch-card"><?php $keywordValues=json_decode((string)($item['keywords']??'[]'),true);if(!is_array($keywordValues))$keywordValues=[];?><form method="post" class="crop autosave"><input type="hidden" name="id" value="<?=$id?>"><input type="hidden" name="draft_id" value="<?=(int)$item['id']?>"><input type="hidden" name="csrf" value="<?=pbh($_SESSION['pinterest_batch_csrf'])?>"><input type="hidden" name="action" value="save_crop"><input type="hidden" name="crop_x" value="<?=pbh($item['crop_x']??.5)?>"><input type="hidden" name="crop_y" value="<?=pbh($item['crop_y']??.5)?>"><canvas width="400" height="600" data-source="media.php?file=<?=rawurlencode(basename((string)$item['mockup_file']))?>"></canvas><label>Zoom <input name="crop_zoom" type="range" min="1" max="3" step=".01" value="<?=pbh($item['crop_zoom']??1)?>"></label></form><form method="post" class="board-form autosave"><input type="hidden" name="id" value="<?=$id?>"><input type="hidden" name="draft_id" value="<?=(int)$item['id']?>"><input type="hidden" name="csrf" value="<?=pbh($_SESSION['pinterest_batch_csrf'])?>"><input type="hidden" name="action" value="save_boards"><span class="boards-label">1 · Pinterest boards</span><div class="boards"><?php foreach($boards as $board):$bid=(string)($board['id']??'');$done=isset($published[$bid]);?><label class="board <?=$done?'published':''?>"><input type="checkbox" name="board_ids[]" value="<?=pbh($bid)?>" <?=in_array($bid,$selected,true)?'checked':''?> <?=$done?'disabled':''?>><?=pbh($board['name']??'Untitled')?><?=$done?' · Published':''?></label><?php endforeach;?></div></form><form method="post" class="content-form autosave"><input type="hidden" name="id" value="<?=$id?>"><input type="hidden" name="draft_id" value="<?=(int)$item['id']?>"><input type="hidden" name="csrf" value="<?=pbh($_SESSION['pinterest_batch_csrf'])?>"><input type="hidden" name="action" value="save_content"><label><span class="content-label">2 · Title</span><input type="text" name="title" maxlength="100" value="<?=pbh($item['title'])?>" required></label><label><span class="content-label">3 · Description</span><textarea name="description" rows="4" maxlength="500"><?=pbh($item['description'])?></textarea></label><label><span class="content-label">4 · Alt text</span><textarea name="alt_text" rows="3" maxlength="500"><?=pbh($item['alt_text'])?></textarea></label></form><form method="post" class="autosave destination-form"><input type="hidden" name="id" value="<?=$id?>"><input type="hidden" name="draft_id" value="<?=(int)$item['id']?>"><input type="hidden" name="csrf" value="<?=pbh($_SESSION['pinterest_batch_csrf'])?>"><input type="hidden" name="action" value="save_destination"><input aria-label="Destination link" type="url" name="destination_url" value="<?=pbh($item['destination_url'])?>" placeholder="5 · Destination link https://..." required></form><?php if($keywordValues):?><span class="content-label">Analysis keywords · internal support</span><div class="keyword-list"><?php foreach($keywordValues as $keyword):?><span><?=pbh($keyword)?></span><?php endforeach;?></div><?php endif;?><span class="status">6 · Publish immediately · one Pin per selected board</span><span class="status" data-save-status>Saved automatically</span><?php $failedMessages=array_values(array_unique(array_filter(array_map(static fn($destination)=>(($destination['status']??'')==='failed'?trim((string)($destination['error']??'')):''),$destinations))));foreach($failedMessages as $failedMessage):?><p class="pin-error"><?=pbh($failedMessage)?></p><?php endforeach;?></article>
<?php endforeach;?></div><section class="batch-card" style="margin-top:22px"><h2>Publish batch</h2><form id="publish-batch" method="post" action="pinterest_batch_publish.php"><input type="hidden" name="id" value="<?=$id?>"><input type="hidden" name="csrf" value="<?=pbh($_SESSION['pinterest_batch_publish_csrf'])?>"><label><input type="checkbox" name="confirm" value="yes" required> I reviewed these mockups and approve this batch.</label><p><button class="button-link primary">Publish batch</button></p></form><small>Destination, boards and crop are saved automatically.</small></section></div></main></div>
<script>
const pendingSaves=new Set();
function autoSave(form){const status=form.closest('.batch-card')?.querySelector('[data-save-status]');if(status)status.textContent='Saving…';const request=fetch('pinterest_batch_autosave.php',{method:'POST',body:new FormData(form),credentials:'same-origin'}).then(async r=>{const data=await r.json();if(!r.ok||!data.ok)throw new Error(data.error||'Could not save');if(status)status.textContent='Saved automatically';}).catch(e=>{if(status)status.textContent=e.message;throw e;}).finally(()=>pendingSaves.delete(request));pendingSaves.add(request);return request;}
document.querySelectorAll('.destination-form input[type=url]').forEach(input=>input.addEventListener('change',()=>autoSave(input.form)));
document.querySelectorAll('.content-form input,.content-form textarea').forEach(input=>input.addEventListener('change',()=>autoSave(input.form)));
document.querySelectorAll('.board-form').forEach(f=>f.onchange=e=>{if(e.target.type==='checkbox'&&f.querySelectorAll('input:checked').length>3){e.target.checked=false;alert('Choose up to 3 boards.');return;}autoSave(f)});
document.querySelectorAll('.crop').forEach(f=>{const c=f.querySelector('canvas'),x=f.querySelector('[name=crop_x]'),y=f.querySelector('[name=crop_y]'),z=f.querySelector('[name=crop_zoom]'),ctx=c.getContext('2d'),img=new Image();let drag=false,lx=0,ly=0;const draw=()=>{if(!img.naturalWidth)return;const s=Math.max(c.width/img.naturalWidth,c.height/img.naturalHeight)*(+z.value),cw=c.width/s,ch=c.height/s;ctx.drawImage(img,(img.naturalWidth-cw)*(+x.value),(img.naturalHeight-ch)*(+y.value),cw,ch,0,0,c.width,c.height)};img.onload=draw;img.src=c.dataset.source;z.oninput=draw;z.onchange=()=>autoSave(f);c.onpointerdown=e=>{drag=true;lx=e.clientX;ly=e.clientY;c.setPointerCapture(e.pointerId)};c.onpointermove=e=>{if(!drag)return;x.value=Math.max(0,Math.min(1,+x.value-(e.clientX-lx)/c.clientWidth));y.value=Math.max(0,Math.min(1,+y.value-(e.clientY-ly)/c.clientHeight));lx=e.clientX;ly=e.clientY;draw()};c.onpointerup=()=>{if(drag){drag=false;autoSave(f)}}});
document.getElementById('publish-batch').addEventListener('submit',async e=>{if(pendingSaves.size){e.preventDefault();const form=e.currentTarget;try{await Promise.all([...pendingSaves]);form.submit()}catch(error){alert('Finish correcting the fields marked with an error before publishing.')}}});
</script></body></html>
